const markdownIt = require('markdown-it');

const abbreviation = require('markdown-it-abbr');
const deflist = require('markdown-it-deflist');
const footnote = require('markdown-it-footnote');
const insert = require('markdown-it-ins');
const mark = require('markdown-it-mark');
const highlightjs = require('markdown-it-highlightjs');
const subscript = require('markdown-it-sub');
const superscript = require('markdown-it-sup');
const tasklists = require('markdown-it-task-lists');

module.exports = {
  md: new markdownIt(),

  template: '<div><slot></slot></div>',
  
  data() {
    return {
      sourceData: this.source,
    };
  },

  props: {
    watches: {
      type: Array,
      default: () => ['source', 'show'],
    },
    source: {
      type: String,
      default: '',
    },
    show: {
      type: Boolean,
      default: true,
    },
    highlight: {
      type: Boolean,
      default: true
    },
    html: {
      type: Boolean,
      default: false,
    },
    xhtmlOut: {
      type: Boolean,
      default: true,
    },
    breaks: {
      type: Boolean,
      default: true,
    },
    linkify: {
      type: Boolean,
      default: true,
    },
    typographer: {
      type: Boolean,
      default: true,
    },
    langPrefix: {
      type: String,
      default: 'language-',
    },
    quotes: {
      type: String,
      default: '“”‘’',
    },
    tableClass: {
      type: String,
      default: 'table',
    },
    taskLists: {
      type: Boolean,
      default: true,
    },
    anchorAttributes: {
      type: Object,
      default: () => ({}),
    },
    prerender: {
      type: Function,
      default: sourceData => sourceData,
    },
    postrender: {
      type: Function,
      default: htmlData => htmlData,
    },
    plugins: {
      type: Array,
      default: () => [],
    },
    options: {
      type: Object,
      default: () => ({}),
    },
  },

  render(createElement) {
    this.md = new markdownIt()
      .use(abbreviation)
      .use(deflist)
      .use(footnote)
      .use(insert)
      .use(mark)
      .use(highlightjs)
      .use(subscript)
      .use(superscript)
      .use(tasklists, { enabled: this.taskLists });

    this.plugins.forEach(({ plugin, options = {} }) => {
      this.md.use(plugin, options);
    });

    this.md.set({
      html: this.html,
      xhtmlOut: this.xhtmlOut,
      breaks: this.breaks,
      linkify: this.linkify,
      typographer: this.typographer,
      langPrefix: this.langPrefix,
      quotes: this.quotes,
    });

    // Customizations

    this.md.renderer.rules.table_open = () => `<table class="${this.tableClass}">\n`;

    const defaultLinkRenderer = this.md.renderer.rules.link_open || function (tokens, idx, options, env, self) {
      return self.renderToken(tokens, idx, options);
    };

    this.md.renderer.rules.link_open = (tokens, idx, options, env, self) => {
      Object.keys(this.anchorAttributes).map((attribute) => {
        const aIndex = tokens[idx].attrIndex(attribute);
        const value = this.anchorAttributes[attribute];

        if (aIndex < 0) {
          tokens[idx].attrPush([attribute, value]); // add new attribute
        } else {
          tokens[idx].attrs[aIndex][1] = value;
        }
      });

      return defaultLinkRenderer(tokens, idx, options, env, self);
    }

    // Render

    let outHtml = this.show ? this.md.render(this.prerender(this.sourceData)) : '';
    outHtml = this.postrender(outHtml);

    this.$emit('rendered', outHtml);

    return createElement('div', {
      domProps: {
        innerHTML: outHtml,
      },
    });
  },

  beforeMount() {
    if (this.$slots.default) {
      this.sourceData = '';

      for (const slot of this.$slots.default) {
        this.sourceData += slot.text;
      }
    }

    this.$watch('source', () => {
      this.sourceData = this.prerender(this.source);
      this.$forceUpdate();
    });

    this.watches.forEach(v => {
      this.$watch(v, () => {
        this.$forceUpdate();
      });
    });
  },
};
